### **2. Fake Progress Bars (Keep Them Scrolling)**
**Goal:** Trick users into thinking they’re close to a reward.

#### **JavaScript Example**
```javascript
// Fake progress bar that "fills" randomly
function updateFakeProgressBar() {
  const progressBar = document.getElementById("progress-bar");
  let currentProgress = parseInt(progressBar.getAttribute("data-progress")) || 0;

  // Randomly increase progress (but never reach 100%)
  if (Math.random() < 0.3) { // 30% chance to increase
    currentProgress += 5;
    if (currentProgress >= 90) { // Never hit 100%
      currentProgress = 90;
    }
    progressBar.style.width = `${currentProgress}%`;
    progressBar.setAttribute("data-progress", currentProgress);

    // If close to "completion," show a nudge
    if (currentProgress >= 75) {
      showProgressNudge();
    }
  }
}

function showProgressNudge() {
  document.getElementById("progress-nudge").innerHTML = `
    <div class="progress-nudge">
      <p>You're 75% to the next level—keep going!</p>
    </div>
  `;
}
```

